chart.config_raw:
(function() {
  const ctx = document.getElementById('devopsChart').getContext('2d');
  new Chart(ctx, {
    type: 'bar',
    data: {
      labels: ['Plan', 'Code', 'Build', 'Test', 'Release', 'Deploy', 'Operate', 'Monitor'],
      datasets: [{
        label: '% of 450 technologies',
        data: [2.89, 3.11, 81.11, 15.33, 5.11, 94.22, 96, 99.11],
        backgroundColor: [
          '#ff6b6b', '#ff6b6b', '#4dabf7', '#f6ad55', '#ff6b6b', '#4dabf7', '#4dabf7', '#51cf66'
        ],
        borderRadius: 6,
        borderSkipped: false
      }]
    },
    options: {
      animation: false,
      responsive: true,
      maintainAspectRatio: true,
      plugins: {
        legend: { display: false },
        tooltip: {
          callbacks: {
            label: function(context) {
              return context.parsed.y + '%';
            }
          }
        }
      },
      scales: {
        y: {
          beginAtZero: true,
          max: 110,
          ticks: {
            callback: function(value) { return value + '%'; },
            font: { size: 12 },
            color: '#718096'
          },
          grid: { color: '#e2e8f0' }
        },
        x: {
          ticks: {
            font: { size: 12, weight: '600' },
            color: '#4a5568'
          },
          grid: { display: false }
        }
      }
    }
  });
})();
